# Before (news.py was deleted, this crashed at import time):
from news import check_updates

# After (inline implementation using feedparser, already in venv):
import feedparser, datetime as _dt

def _check_updates(sources: list[dict]) -> list[dict]:
    items = []
    for src in sources:
        url, label = src.get(url, ), src.get(label, )
        try:
            feed = feedparser.parse(url)
            for entry in feed.entries:
                items.append({
                    url: entry.get(link, ), title: entry.get(title, ),
                    text: entry.get(summary, ),
                    seen_at: _dt.datetime.utcnow().strftime(%Y-%m-%dT%H:%M:%SZ),
                    source_label: label,
                })
        except Exception as exc:
            items.append({url: None, error: str(exc), source_label: label})
    return items
